import { Truck, Package, CheckCircle2, AlertTriangle } from 'lucide-react';

const statDefinitions = [
    { key: 'Pending', label: 'To Be Picked', icon: Truck, color: '#facc15' },
    { key: 'Shipped', label: 'Shipped', icon: Package, color: '#3b82f6' },
    { key: 'Delivered', label: 'Delivered', icon: CheckCircle2, color: '#22c55e' },
    { key: 'Urgent', label: 'High Urgency', icon: AlertTriangle, color: '#ef4444' },
];

function StatCards({ orders }) {
    const counts = {
        Pending: 0,
        Shipped: 0,
        Delivered: 0,
        Urgent: 0,
    };

    for (const order of orders) {
        if (order.status === 'Pending') counts.Pending += 1;
        if (order.status === 'Shipped') counts.Shipped += 1;
        if (order.status === 'Delivered') counts.Delivered += 1;
        if (order.urgency === 5) counts.Urgent += 1;
    }

    return (
        <div className="content-grid" style={{ gridTemplateColumns: 'repeat(4, minmax(0, 1fr))', marginBottom: '14px' }}>
            {statDefinitions.map((item) => {
                const Icon = item.icon;
                const value = item.key === 'Urgent' ? counts.Urgent : counts[item.key] ?? 0;

                return (
                    <div key={item.key} className="preview-card" style={{ display: 'flex', alignItems: 'center', gap: '12px', borderLeft: `4px solid ${item.color}` }}>
                        <Icon color={item.color} size={28} />
                        <div>
                            <div style={{ color: '#6b7280', fontSize: '.82rem', textTransform: 'uppercase', letterSpacing: '.04em' }}>{item.label}</div>
                            <div style={{ fontSize: '1.4rem', fontWeight: 700 }}>{value}</div>
                        </div>
                    </div>
                );
            })}
        </div>
    );
}

export default StatCards;
